-- ── Administrative Safeguards (§ 164.308) ──────────────────────────────────
('c0000000-0000-0000-0000-419a4a000001', 'AS', 'Administrative Safeguards', 'Administrative Schutzmaßnahmen', 'Administrative actions, policies and procedures to manage the selection, development, implementation and maintenance of security measures', 'Administrative Maßnahmen, Richtlinien und Verfahren zur Verwaltung der Sicherheitsmaßnahmen', 0, 100, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(1)', 'Security Management Process [R]', 'Sicherheits-Managementprozess [R]', 'Implement policies and procedures to prevent, detect, contain and correct security violations', 'Richtlinien und Verfahren zur Verhinderung, Erkennung, Eindämmung und Korrektur von Sicherheitsverletzungen implementieren', 1, 110, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(1)(ii)(A)', 'Risk Analysis [R]', 'Risikoanalyse [R]', 'Conduct an accurate and thorough assessment of the potential risks to ePHI', 'Genaue und gründliche Bewertung möglicher Risiken für ePHI durchführen', 2, 111, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(1)(ii)(B)', 'Risk Management [R]', 'Risikomanagement [R]', 'Implement security measures sufficient to reduce risks to a reasonable and appropriate level', 'Sicherheitsmaßnahmen implementieren, um Risiken auf ein angemessenes Niveau zu reduzieren', 2, 112, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(1)(ii)(C)', 'Sanction Policy [R]', 'Sanktionsrichtlinie [R]', 'Apply appropriate sanctions against workforce members who fail to comply with policies', 'Angemessene Sanktionen gegen Mitarbeiter, die Richtlinien nicht einhalten, anwenden', 2, 113, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(1)(ii)(D)', 'Information System Activity Review [R]', 'Überprüfung Systemaktivität [R]', 'Implement procedures to regularly review records of information-system activity', 'Verfahren zur regelmäßigen Überprüfung der Systemaktivitäts-Aufzeichnungen implementieren', 2, 114, 'active'),

('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(2)', 'Assigned Security Responsibility [R]', 'Zugewiesene Sicherheitsverantwortung [R]', 'Identify the security official responsible for the development and implementation of security policies and procedures', 'Den Sicherheitsverantwortlichen für Entwicklung und Implementierung der Sicherheitsrichtlinien benennen', 1, 120, 'active'),

('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(3)', 'Workforce Security [R]', 'Personalsicherheit [R]', 'Implement procedures to ensure all workforce members have appropriate access to ePHI and prevent unauthorized access', 'Verfahren implementieren, dass alle Mitarbeiter angemessenen Zugang zu ePHI haben und unbefugter Zugang verhindert wird', 1, 130, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(3)(ii)(A)', 'Authorization and/or Supervision [A]', 'Autorisierung/Überwachung [A]', 'Implement procedures for the authorization and/or supervision of workforce members who work with ePHI', 'Verfahren für Autorisierung/Überwachung von Mitarbeitern mit ePHI-Zugriff implementieren', 2, 131, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(3)(ii)(B)', 'Workforce Clearance Procedure [A]', 'Personal-Clearance-Verfahren [A]', 'Implement procedures to determine that the access of a workforce member to ePHI is appropriate', 'Verfahren implementieren, um festzustellen, dass der ePHI-Zugang eines Mitarbeiters angemessen ist', 2, 132, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(3)(ii)(C)', 'Termination Procedures [A]', 'Beendigungsverfahren [A]', 'Implement procedures for terminating access to ePHI when employment ends', 'Verfahren zur Beendigung des ePHI-Zugangs bei Arbeitsende implementieren', 2, 133, 'active'),

('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(4)', 'Information Access Management [R]', 'Verwaltung Informationszugang [R]', 'Implement policies and procedures for authorizing access to ePHI', 'Richtlinien und Verfahren zur Autorisierung des ePHI-Zugangs implementieren', 1, 140, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(4)(ii)(B)', 'Access Authorization [A]', 'Zugangsautorisierung [A]', 'Implement policies for granting access to ePHI through workstations, transactions, programs, processes', 'Richtlinien für die Gewährung des ePHI-Zugangs über Workstations, Transaktionen, Programme implementieren', 2, 141, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(4)(ii)(C)', 'Access Establishment and Modification [A]', 'Zugangs-Einrichtung und -Änderung [A]', 'Implement policies for establishing, documenting, reviewing and modifying user access to ePHI', 'Richtlinien für Einrichtung, Dokumentation, Überprüfung und Änderung des Benutzerzugangs zu ePHI implementieren', 2, 142, 'active'),

('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(5)', 'Security Awareness and Training [R]', 'Sicherheits-Awareness und Schulung [R]', 'Implement a security awareness and training program for all workforce members', 'Sicherheits-Awareness- und Schulungsprogramm für alle Mitarbeiter implementieren', 1, 150, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(5)(ii)(A)', 'Security Reminders [A]', 'Sicherheitserinnerungen [A]', 'Periodic security updates', 'Regelmäßige Sicherheits-Updates', 2, 151, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(5)(ii)(B)', 'Protection from Malicious Software [A]', 'Schutz vor Schadsoftware [A]', 'Procedures for guarding against, detecting and reporting malicious software', 'Verfahren zum Schutz vor, zur Erkennung und Meldung von Schadsoftware', 2, 152, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(5)(ii)(C)', 'Log-in Monitoring [A]', 'Login-Überwachung [A]', 'Procedures for monitoring log-in attempts and reporting discrepancies', 'Verfahren zur Überwachung von Login-Versuchen und Meldung von Abweichungen', 2, 153, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(5)(ii)(D)', 'Password Management [A]', 'Passwort-Management [A]', 'Procedures for creating, changing and safeguarding passwords', 'Verfahren zur Erstellung, Änderung und zum Schutz von Passwörtern', 2, 154, 'active'),

('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(6)', 'Security Incident Procedures [R]', 'Sicherheitsvorfall-Verfahren [R]', 'Implement policies and procedures to address security incidents', 'Richtlinien und Verfahren zur Behandlung von Sicherheitsvorfällen implementieren', 1, 160, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(6)(ii)', 'Response and Reporting [R]', 'Reaktion und Meldung [R]', 'Identify and respond to suspected or known security incidents; mitigate harmful effects; document incidents and outcomes', 'Vermutete oder bekannte Sicherheitsvorfälle identifizieren und darauf reagieren; schädliche Auswirkungen mindern; Vorfälle und Ergebnisse dokumentieren', 2, 161, 'active'),

('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(7)', 'Contingency Plan [R]', 'Notfallplan [R]', 'Establish policies and procedures for responding to an emergency that damages systems containing ePHI', 'Richtlinien und Verfahren für die Reaktion auf Notfälle, die ePHI-Systeme beschädigen, etablieren', 1, 170, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(7)(ii)(A)', 'Data Backup Plan [R]', 'Datensicherungsplan [R]', 'Establish and implement procedures to create and maintain retrievable exact copies of ePHI', 'Verfahren zur Erstellung und Pflege wiederherstellbarer exakter ePHI-Kopien etablieren', 2, 171, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(7)(ii)(B)', 'Disaster Recovery Plan [R]', 'Disaster-Recovery-Plan [R]', 'Establish procedures to restore any loss of data', 'Verfahren zur Wiederherstellung jeglichen Datenverlusts etablieren', 2, 172, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(7)(ii)(C)', 'Emergency Mode Operation Plan [R]', 'Notfall-Betriebsplan [R]', 'Establish procedures to enable continuation of critical business processes for ePHI protection during an emergency', 'Verfahren zur Aufrechterhaltung kritischer Geschäftsprozesse für den ePHI-Schutz im Notfall etablieren', 2, 173, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(7)(ii)(D)', 'Testing and Revision Procedures [A]', 'Test- und Revisionsverfahren [A]', 'Implement procedures for periodic testing and revision of contingency plans', 'Verfahren für regelmäßige Tests und Revision der Notfallpläne implementieren', 2, 174, 'active'),

('c0000000-0000-0000-0000-419a4a000001', '164.308(a)(8)', 'Evaluation [R]', 'Bewertung [R]', 'Perform a periodic technical and nontechnical evaluation that establishes the extent to which security policies and procedures meet the requirements', 'Regelmäßige technische und nicht-technische Bewertung durchführen, die den Erfüllungsgrad der Sicherheitsrichtlinien feststellt', 1, 180, 'active'),

('c0000000-0000-0000-0000-419a4a000001', '164.308(b)(1)', 'Business Associate Contracts [R]', 'Business-Associate-Verträge [R]', 'Permit a business associate to create, receive, maintain or transmit ePHI on the covered entity''s behalf only with satisfactory assurances', 'Business Associate darf ePHI nur mit zufriedenstellenden Zusicherungen verarbeiten', 1, 190, 'active'),

