('c0000000-0000-0000-0000-419a4a000001', '164.310(a)(1)', 'Facility Access Controls [R]', 'Einrichtungs-Zugangskontrollen [R]', 'Implement policies and procedures to limit physical access to systems and facilities', 'Richtlinien und Verfahren zur Begrenzung des physischen Zugangs zu Systemen und Einrichtungen implementieren', 1, 210, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.310(a)(2)(i)', 'Contingency Operations [A]', 'Notfall-Operationen [A]', 'Procedures that allow facility access in support of restoration of lost data', 'Verfahren für den Einrichtungs-Zugang zur Wiederherstellung verlorener Daten', 2, 211, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.310(a)(2)(ii)', 'Facility Security Plan [A]', 'Einrichtungs-Sicherheitsplan [A]', 'Procedures to safeguard the facility and equipment from unauthorized physical access', 'Verfahren zum Schutz der Einrichtung und Geräte vor unbefugtem physischen Zugang', 2, 212, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.310(a)(2)(iii)', 'Access Control and Validation Procedures [A]', 'Zugangskontroll- und Validierungsverfahren [A]', 'Procedures to control and validate a person''s access to facilities based on their role', 'Verfahren zur Steuerung und Validierung des Personen-Zugangs basierend auf ihrer Rolle', 2, 213, 'active'),

('c0000000-0000-0000-0000-419a4a000001', '164.310(b)', 'Workstation Use [R]', 'Workstation-Nutzung [R]', 'Specify proper functions to be performed and the manner in which functions are performed for workstations accessing ePHI', 'Korrekte Funktionen und Ausführungsweise für ePHI-zugreifende Workstations festlegen', 1, 220, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.310(c)', 'Workstation Security [R]', 'Workstation-Sicherheit [R]', 'Implement physical safeguards for all workstations that access ePHI', 'Physische Schutzmaßnahmen für alle ePHI-zugreifenden Workstations implementieren', 1, 230, 'active'),

('c0000000-0000-0000-0000-419a4a000001', '164.310(d)(1)', 'Device and Media Controls [R]', 'Geräte- und Medienkontrollen [R]', 'Implement policies and procedures that govern the receipt and removal of hardware and electronic media that contain ePHI', 'Richtlinien und Verfahren für den Empfang und die Entfernung von ePHI-Hardware/-Medien implementieren', 1, 240, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.310(d)(2)(i)', 'Disposal [R]', 'Entsorgung [R]', 'Procedures for disposal of ePHI and the hardware on which it is stored', 'Verfahren zur Entsorgung von ePHI und der Hardware, auf der es gespeichert ist', 2, 241, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.310(d)(2)(ii)', 'Media Re-use [R]', 'Medien-Wiederverwendung [R]', 'Procedures for removal of ePHI from electronic media before re-use', 'Verfahren zur ePHI-Entfernung von elektronischen Medien vor Wiederverwendung', 2, 242, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.310(d)(2)(iii)', 'Accountability [A]', 'Verantwortlichkeit [A]', 'Maintain a record of the movements of hardware and electronic media and any person responsible', 'Aufzeichnung über Bewegungen von Hardware/Medien und verantwortliche Personen führen', 2, 243, 'active'),

