('c0000000-0000-0000-0000-419a4a000001', 'TS', 'Technical Safeguards', 'Technische Schutzmaßnahmen', 'Technology and policy/procedures for its use that protect ePHI and control access to it', 'Technologie und Richtlinien/Verfahren zum Schutz von ePHI und zur Zugangssteuerung', 0, 300, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.312(a)(1)', 'Access Control [R]', 'Zugangskontrolle [R]', 'Implement technical policies and procedures for electronic information systems that maintain ePHI to allow access only to authorized persons', 'Technische Richtlinien und Verfahren für elektronische ePHI-Informationssysteme implementieren, um Zugang nur autorisierten Personen zu gewähren', 1, 310, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.312(a)(2)(i)', 'Unique User Identification [R]', 'Eindeutige Benutzeridentifikation [R]', 'Assign a unique name and/or number for identifying and tracking user identity', 'Eindeutigen Namen/Nummer zur Identifikation und Nachverfolgung der Benutzeridentität zuweisen', 2, 311, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.312(a)(2)(ii)', 'Emergency Access Procedure [R]', 'Notfallzugangs-Verfahren [R]', 'Procedures for obtaining necessary ePHI during an emergency', 'Verfahren zur Beschaffung notwendiger ePHI während eines Notfalls', 2, 312, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.312(a)(2)(iii)', 'Automatic Logoff [A]', 'Automatischer Logoff [A]', 'Procedures that terminate an electronic session after a predetermined time of inactivity', 'Verfahren zur Beendigung einer elektronischen Sitzung nach festgelegter Inaktivitätszeit', 2, 313, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.312(a)(2)(iv)', 'Encryption and Decryption [A]', 'Verschlüsselung/Entschlüsselung [A]', 'Mechanism to encrypt and decrypt ePHI', 'Mechanismus zur Ver-/Entschlüsselung von ePHI', 2, 314, 'active'),

('c0000000-0000-0000-0000-419a4a000001', '164.312(b)', 'Audit Controls [R]', 'Audit-Kontrollen [R]', 'Implement hardware, software and/or procedural mechanisms that record and examine activity in information systems containing ePHI', 'Hardware-, Software- und Verfahrensmechanismen implementieren, die Aktivitäten in ePHI-Systemen aufzeichnen und prüfen', 1, 320, 'active'),

('c0000000-0000-0000-0000-419a4a000001', '164.312(c)(1)', 'Integrity [R]', 'Integrität [R]', 'Implement policies and procedures to protect ePHI from improper alteration or destruction', 'Richtlinien und Verfahren zum Schutz von ePHI vor unsachgemäßer Änderung/Zerstörung implementieren', 1, 330, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.312(c)(2)', 'Mechanism to Authenticate ePHI [A]', 'Mechanismus zur ePHI-Authentifizierung [A]', 'Electronic mechanisms to corroborate that ePHI has not been altered or destroyed in unauthorized manner', 'Elektronische Mechanismen zur Bestätigung, dass ePHI nicht unbefugt geändert oder zerstört wurde', 2, 331, 'active'),

('c0000000-0000-0000-0000-419a4a000001', '164.312(d)', 'Person or Entity Authentication [R]', 'Personen-/Entity-Authentifizierung [R]', 'Implement procedures to verify that a person or entity seeking access to ePHI is the one claimed', 'Verfahren zur Verifikation implementieren, dass die Person/Entity, die Zugang zu ePHI sucht, die behauptete ist', 1, 340, 'active'),

('c0000000-0000-0000-0000-419a4a000001', '164.312(e)(1)', 'Transmission Security [R]', 'Übertragungssicherheit [R]', 'Implement technical security measures to guard against unauthorized access to ePHI being transmitted over a network', 'Technische Sicherheitsmaßnahmen gegen unbefugten Zugang zu netzwerkübertragenen ePHI implementieren', 1, 350, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.312(e)(2)(i)', 'Integrity Controls [A]', 'Integritäts-Kontrollen [A]', 'Security measures to ensure ePHI is not improperly modified during transmission', 'Sicherheitsmaßnahmen zur Sicherstellung, dass ePHI während der Übertragung nicht unsachgemäß geändert wird', 2, 351, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.312(e)(2)(ii)', 'Encryption [A]', 'Verschlüsselung [A]', 'Mechanism to encrypt ePHI whenever deemed appropriate', 'Mechanismus zur Verschlüsselung von ePHI, wo angemessen', 2, 352, 'active'),

