('c0000000-0000-0000-0000-419a4a000001', 'OR', 'Organizational Requirements', 'Organisatorische Anforderungen', 'Business associate contracts and group-health-plan requirements', 'Business-Associate-Verträge und Gruppen-Krankenversicherungs-Anforderungen', 0, 400, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.314(a)(1)', 'Business Associate Contracts [R]', 'Business-Associate-Verträge [R]', 'BAA shall provide that the business associate will safeguard ePHI', 'BAA muss vorsehen, dass der Business Associate ePHI schützt', 1, 410, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.314(b)(1)', 'Group Health Plan Requirements [R]', 'Gruppen-Krankenversicherungs-Anforderungen [R]', 'Group health plan plan documents shall be amended to incorporate provisions', 'Plandokumente einer Gruppen-Krankenversicherung müssen Bestimmungen enthalten', 1, 420, 'active'),

('c0000000-0000-0000-0000-419a4a000001', 'DOC', 'Documentation Requirements', 'Dokumentationsanforderungen', 'Maintain policies, procedures and required actions, activities and assessments', 'Richtlinien, Verfahren und erforderliche Aktionen, Aktivitäten und Bewertungen führen', 0, 500, 'active'),
