('c0000000-0000-0000-0000-419a4a000001', '164.316(b)(1)', 'Documentation [R]', 'Dokumentation [R]', 'Maintain in written or electronic form the policies and procedures and a written record of any action, activity or assessment required', 'Richtlinien und Verfahren sowie schriftliche Aufzeichnungen erforderlicher Aktionen schriftlich/elektronisch führen', 1, 520, 'active'),
('c0000000-0000-0000-0000-419a4a000001', '164.316(b)(2)(i)', 'Time Limit [R]', 'Aufbewahrungsfrist [R]', 'Retain documentation for 6 years from creation or last effective date, whichever is later', 'Dokumentation für 6 Jahre ab Erstellung oder letztem Wirksamkeitsdatum, je nachdem was später ist, aufbewahren', 2, 521, 'active'),
